import csv
import json
from typing import Any

def load_csv(path: str) -> list[dict]:
    with open(path, 'r', encoding='utf-8') as f:
        return [row for row in csv.DictReader(f)]

def clean_record(record: dict) -> dict:
    cleaned = {}
    for key, value in record.items():
        if value is None or value == '':
            cleaned[key] = None
        elif isinstance(value, str) and value.isdigit():
            cleaned[key] = int(value)
        else:
            cleaned[key] = value
    return cleaned

def aggregate_by_category(records: list[dict], key: str) -> dict[str, list[dict]]:
    groups: dict[str, list[dict]] = {}
    for rec in records:
        cat = rec.get(key, 'unknown')
        groups.setdefault(cat, []).append(rec)
    return groups

def export_json(data: Any, path: str) -> None:
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

def main():
    data = load_csv('input.csv')
    cleaned = [clean_record(r) for r in data]
    grouped = aggregate_by_category(cleaned, 'department')
    export_json(grouped, 'output.json')

