import hashlib
import secrets
import sqlite3

class UserAuth:
    def __init__(self, db_path: str = ':memory:'):
        self.conn = sqlite3.connect(db_path)
        self.conn.execute(
            "CREATE TABLE IF NOT EXISTS users ("
            "id INTEGER PRIMARY KEY, name TEXT UNIQUE, pwd_hash TEXT, salt TEXT)"
        )

    def _hash_pwd(self, password: str, salt: str = None) -> tuple[str, str]:
        salt = salt or secrets.token_hex(16)
        digest = hashlib.pbkdf2_hmac(
            'sha256', password.encode(), salt.encode(), 200_000
        ).hex()
        return digest, salt

    def register(self, username: str, password: str) -> bool:
        if not username or not password:
            raise ValueError("用户名和密码不能为空")
        pwd_hash, salt = self._hash_pwd(password)
        self.conn.execute(
            "INSERT INTO users (name, pwd_hash, salt) VALUES (?, ?, ?)",
            (username, pwd_hash, salt)
        )
        self.conn.commit()
        return True

    def login(self, username: str, password: str) -> dict | None:
        row = self.conn.execute(
            "SELECT pwd_hash, salt FROM users WHERE name = ?", (username,)
        ).fetchone()
        if not row:
            return None
        pwd_hash, salt = row
        attempt_hash, _ = self._hash_pwd(password, salt)
        if not secrets.compare_digest(attempt_hash, pwd_hash):
            return None
        token = secrets.token_urlsafe(32)
        return {'token': token, 'role': 'user'}
